import{_ as e,c as t,o,a2 as d}from"./chunks/framework.DdOM6S6U.js";const y=JSON.parse('{"title":"Module Features Overview","description":"","frontmatter":{"sidebarPos":0,"sidebarTitle":"Module Features Overview"},"headers":[],"relativePath":"guide/module-features/index.md","filePath":"guide/module-features/index.md","lastUpdated":null}'),a={name:"guide/module-features/index.md"},r=d('<h1 id="module-features-overview" tabindex="-1">Module Features Overview <a class="header-anchor" href="#module-features-overview" aria-label="Permalink to &quot;Module Features Overview&quot;">​</a></h1><p>Modularity module features follow a <strong>triple pattern</strong>: Entity trait + Repository trait + Hydrate. Each layer handles a specific concern.</p><p>See <a href="/system-reference/features">Features Pattern</a> for the full pattern explanation. For generics (Allowable, Relationships, Files and Media, etc.), see <a href="/guide/generics/">Generics</a>.</p><table><thead><tr><th>Layer</th><th>Location</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Entity trait</strong></td><td><code>Entities/Traits/Has*.php</code></td><td>Model relationships, boot logic, accessors</td></tr><tr><td><strong>Repository trait</strong></td><td><code>Repositories/Traits/*Trait.php</code></td><td>Persistence: hydrate, afterSave, getFormFields</td></tr><tr><td><strong>Hydrate</strong></td><td><code>Hydrates/Inputs/*Hydrate.php</code></td><td>Schema transformation for form input</td></tr></tbody></table><h2 id="feature-matrix" tabindex="-1">Feature Matrix <a class="header-anchor" href="#feature-matrix" aria-label="Permalink to &quot;Feature Matrix&quot;">​</a></h2><table><thead><tr><th>Feature</th><th>Config type</th><th>Entity Trait</th><th>Repository Trait</th><th>Hydrate</th><th>Output type</th></tr></thead><tbody><tr><td><a href="#media--images">Media/Images</a></td><td><code>image</code></td><td>HasImages</td><td>ImagesTrait</td><td>ImageHydrate</td><td>input-image</td></tr><tr><td><a href="#files">Files</a></td><td><code>file</code></td><td>HasFiles</td><td>FilesTrait</td><td>FileHydrate</td><td>input-file</td></tr><tr><td><a href="#filepond">Filepond</a></td><td><code>filepond</code></td><td>HasFileponds</td><td>FilepondsTrait</td><td>FilepondHydrate</td><td>input-filepond</td></tr><tr><td><a href="#spread">Spread</a></td><td><code>spread</code></td><td>HasSpreadable</td><td>SpreadableTrait</td><td>SpreadHydrate</td><td>input-spread</td></tr><tr><td><a href="#slug">Slug</a></td><td>—</td><td>HasSlug</td><td>SlugsTrait</td><td>—</td><td>—</td></tr><tr><td><a href="#authorizable">Authorizable</a></td><td><code>authorize</code></td><td>HasAuthorizable</td><td>AuthorizableTrait</td><td>AuthorizeHydrate</td><td>select</td></tr><tr><td><a href="#creator">Creator</a></td><td><code>creator</code></td><td>HasCreator</td><td>CreatorTrait</td><td>CreatorHydrate</td><td>input-browser</td></tr><tr><td><a href="#payment">Payment</a></td><td><code>price</code>, <code>payment-service</code></td><td>HasPayment</td><td>PaymentTrait</td><td>—</td><td>—</td></tr><tr><td><a href="#priceable">Priceable</a></td><td><code>price</code></td><td>HasPriceable</td><td>PricesTrait</td><td>PriceHydrate</td><td>input-price</td></tr><tr><td><a href="#position">Position</a></td><td>—</td><td>HasPosition</td><td>—</td><td>—</td><td>—</td></tr><tr><td><a href="#repeaters">Repeaters</a></td><td><code>repeater</code></td><td>HasRepeaters</td><td>RepeatersTrait</td><td>RepeaterHydrate</td><td>input-repeater</td></tr><tr><td><a href="#singular">Singular</a></td><td>—</td><td>IsSingular</td><td>—</td><td>—</td><td>—</td></tr><tr><td><a href="#stateable">Stateable</a></td><td><code>stateable</code></td><td>HasStateable</td><td>StateableTrait</td><td>StateableHydrate</td><td>select</td></tr><tr><td><a href="#processable">Processable</a></td><td><code>process</code></td><td>Processable</td><td>ProcessableTrait</td><td>ProcessHydrate</td><td>input-process</td></tr><tr><td><a href="#chatable">Chatable</a></td><td><code>chat</code></td><td>Chatable</td><td>—</td><td>ChatHydrate</td><td>input-chat</td></tr><tr><td><a href="#assignable">Assignable</a></td><td><code>assignment</code></td><td>Assignable</td><td>AssignmentTrait</td><td>AssignmentHydrate</td><td>input-assignment</td></tr><tr><td><a href="#translation">Translation</a></td><td><code>translated: true</code></td><td>IsTranslatable, HasTranslation</td><td>TranslationsTrait</td><td>—</td><td>—</td></tr></tbody></table><hr><h2 id="media-images" tabindex="-1">Media / Images <a class="header-anchor" href="#media-images" aria-label="Permalink to &quot;Media / Images&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasImages</code> — morphToMany with Media; role-based, locale-aware; <code>media()</code>, <code>findMedia()</code>, <code>image()</code>, <code>imagesList()</code>.</p><p><strong>Repository</strong>: <code>ImagesTrait</code> — <code>setColumnsImagesTrait</code>, <code>hydrateImagesTrait</code>, <code>afterSaveImagesTrait</code>, <code>getFormFieldsImagesTrait</code>.</p><p><strong>Hydrate</strong>: <code>ImageHydrate</code> — type → <code>input-image</code>, default name <code>images</code>.</p><hr><h2 id="files" tabindex="-1">Files <a class="header-anchor" href="#files" aria-label="Permalink to &quot;Files&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasFiles</code> — morphToMany with File; role/locale pivot; <code>files()</code>, <code>file()</code>, <code>filesList()</code>, <code>fileObject()</code>.</p><p><strong>Repository</strong>: <code>FilesTrait</code> — <code>setColumnsFilesTrait</code>, <code>hydrateFilesTrait</code>, <code>afterSaveFilesTrait</code>, <code>getFormFieldsFilesTrait</code>. Syncs pivot via <code>file_id</code>, <code>role</code>, <code>locale</code>.</p><p><strong>Hydrate</strong>: <code>FileHydrate</code> — type → <code>input-file</code>, default name <code>files</code>.</p><hr><h2 id="filepond" tabindex="-1">Filepond <a class="header-anchor" href="#filepond" aria-label="Permalink to &quot;Filepond&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasFileponds</code> — morphMany Filepond; <code>fileponds()</code>, <code>getFileponds()</code>, <code>hasFilepond()</code>. One-to-many direct binding (no file library).</p><p><strong>Repository</strong>: <code>FilepondsTrait</code> — Handles filepond sync, temp file conversion.</p><p><strong>Hydrate</strong>: <code>FilepondHydrate</code> — type → <code>input-filepond</code>; sets <code>endPoints</code> (process, revert, load), <code>max-files</code>, <code>accepted-file-types</code>, labels.</p><hr><h2 id="spread" tabindex="-1">Spread <a class="header-anchor" href="#spread" aria-label="Permalink to &quot;Spread&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasSpreadable</code> — Stores flexible JSON in a Spread model; <code>getSpreadableSavingKey()</code>, <code>spreadable()</code>.</p><p><strong>Repository</strong>: <code>SpreadableTrait</code> — Persists spread payload.</p><p><strong>Hydrate</strong>: <code>SpreadHydrate</code> — type → <code>input-spread</code>; <code>reservedKeys</code> from route inputs; <code>name</code> from <code>getSpreadableSavingKey()</code>.</p><hr><h2 id="slug" tabindex="-1">Slug <a class="header-anchor" href="#slug" aria-label="Permalink to &quot;Slug&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasSlug</code> — hasMany Slug; <code>slugs()</code>, <code>getSlugClass()</code>, <code>setSlugs()</code>. URL slugs per locale.</p><p><strong>Repository</strong>: <code>SlugsTrait</code> — Slug persistence.</p><p><strong>Hydrate</strong>: None (slug is derived from route/translatable fields).</p><hr><h2 id="authorizable" tabindex="-1">Authorizable <a class="header-anchor" href="#authorizable" aria-label="Permalink to &quot;Authorizable&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasAuthorizable</code> — morphOne Authorization; <code>authorizationRecord()</code>, <code>authorized_id</code>, <code>authorized_type</code>. Assigns an authorized model (e.g. User).</p><p><strong>Repository</strong>: <code>AuthorizableTrait</code> — Syncs authorization record.</p><p><strong>Hydrate</strong>: <code>AuthorizeHydrate</code> — type → <code>select</code>; <code>name</code> = <code>authorized_id</code>; resolves <code>authorized_type</code> from model; <code>scopeRole</code> filters by Spatie role.</p><hr><h2 id="creator" tabindex="-1">Creator <a class="header-anchor" href="#creator" aria-label="Permalink to &quot;Creator&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasCreator</code> — morphOne CreatorRecord; <code>creator()</code>, <code>custom_creator_id</code>. Tracks who created the record.</p><p><strong>Repository</strong>: <code>CreatorTrait</code> — <code>setColumnsCreatorTrait</code>, <code>hydrateCreatorTrait</code>, <code>afterSaveCreatorTrait</code>.</p><p><strong>Hydrate</strong>: <code>CreatorHydrate</code> — type → <code>input-browser</code>; <code>name</code> = <code>custom_creator_id</code>; endpoint → <code>admin.system.user.index</code>; <code>allowedRoles</code> (e.g. superadmin).</p><hr><h2 id="payment" tabindex="-1">Payment <a class="header-anchor" href="#payment" aria-label="Permalink to &quot;Payment&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasPayment</code> — uses <code>HasPriceable</code>; links to SystemPayment module; <code>paymentPrice</code>, <code>paidPrices</code>; <code>PaymentStatus</code> enum.</p><p><strong>Repository</strong>: <code>PaymentTrait</code> — Payment-related persistence.</p><p><strong>Hydrate</strong>: None (uses PriceHydrate for price inputs). <code>PaymentServiceHydrate</code> for payment service selection.</p><hr><h2 id="priceable" tabindex="-1">Priceable <a class="header-anchor" href="#priceable" aria-label="Permalink to &quot;Priceable&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasPriceable</code> — morphMany Price (SystemPricing); <code>prices()</code>, <code>basePrice()</code>, <code>originalBasePrice()</code>; language-based pricing via CurrencyExchange.</p><p><strong>Repository</strong>: <code>PricesTrait</code> — Price sync.</p><p><strong>Hydrate</strong>: <code>PriceHydrate</code> — type → <code>input-price</code>; <code>items</code> from CurrencyProvider; optional <code>vatRates</code>; <code>hasVatRate</code>.</p><hr><h2 id="position" tabindex="-1">Position <a class="header-anchor" href="#position" aria-label="Permalink to &quot;Position&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasPosition</code> — <code>position</code> column; <code>scopeOrdered()</code>; <code>setNewOrder($ids)</code> for reordering. Auto-sets last position on create.</p><p><strong>Repository</strong>: None (column-only).</p><p><strong>Hydrate</strong>: None.</p><hr><h2 id="repeaters" tabindex="-1">Repeaters <a class="header-anchor" href="#repeaters" aria-label="Permalink to &quot;Repeaters&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasRepeaters</code> — uses HasFiles, HasImages, HasPriceable, HasFileponds; morphMany Repeater; <code>repeaters($role, $locale)</code>.</p><p><strong>Repository</strong>: <code>RepeatersTrait</code> — Repeater CRUD, schema resolution.</p><p><strong>Hydrate</strong>: <code>RepeaterHydrate</code> — type → <code>input-repeater</code>; <code>schema</code> for nested inputs; <code>root</code>, <code>draggable</code>, <code>orderKey</code>.</p><hr><h2 id="singular" tabindex="-1">Singular <a class="header-anchor" href="#singular" aria-label="Permalink to &quot;Singular&quot;">​</a></h2><p><strong>Entity</strong>: <code>IsSingular</code> — Global scope <code>SingularScope</code>; single record per type; <code>singleton_type</code>, <code>content</code> JSON; fillable stored in <code>content</code>.</p><p><strong>Repository</strong>: None (singleton pattern).</p><p><strong>Hydrate</strong>: None.</p><hr><h2 id="stateable" tabindex="-1">Stateable <a class="header-anchor" href="#stateable" aria-label="Permalink to &quot;Stateable&quot;">​</a></h2><p><strong>Entity</strong>: <code>HasStateable</code> — morphOne State; <code>stateable()</code>, <code>stateable_status</code>; workflow states.</p><p><strong>Repository</strong>: <code>StateableTrait</code> — State sync; <code>getStateableList()</code>.</p><p><strong>Hydrate</strong>: <code>StateableHydrate</code> — type → <code>select</code>; <code>name</code> = <code>stateable_id</code>; <code>items</code> from repository <code>getStateableList()</code>.</p><hr><h2 id="processable" tabindex="-1">Processable <a class="header-anchor" href="#processable" aria-label="Permalink to &quot;Processable&quot;">​</a></h2><p><strong>Entity</strong>: <code>Processable</code> — morphOne Process; <code>process()</code>, <code>processHistories()</code>; <code>ProcessStatus</code> enum; <code>setProcessStatus()</code>.</p><p><strong>Repository</strong>: <code>ProcessableTrait</code> — Process lifecycle.</p><p><strong>Hydrate</strong>: <code>ProcessHydrate</code> — type → <code>input-process</code>; requires <code>_moduleName</code>, <code>_routeName</code>; <code>fetchEndpoint</code>, <code>updateEndpoint</code> for process UI.</p><hr><h2 id="chatable" tabindex="-1">Chatable <a class="header-anchor" href="#chatable" aria-label="Permalink to &quot;Chatable&quot;">​</a></h2><p><strong>Entity</strong>: <code>Chatable</code> — morphOne Chat; <code>chat()</code>, <code>chatMessages()</code>; auto-creates Chat on create; appends <code>chat_messages_count</code>, <code>unread_chat_messages_count</code>.</p><p><strong>Repository</strong>: None (Chat/ChatMessage handled by dedicated controllers).</p><p><strong>Hydrate</strong>: <code>ChatHydrate</code> — type → <code>input-chat</code>; <code>endpoints</code> (index, store, show, update, destroy, attachments, pinnedMessage); embeds Filepond for attachments.</p><hr><h2 id="assignable" tabindex="-1">Assignable <a class="header-anchor" href="#assignable" aria-label="Permalink to &quot;Assignable&quot;">​</a></h2><p><strong>Entity</strong>: <code>Assignable</code> — morphMany Assignment; <code>assignments()</code>, <code>activeAssignment()</code>; <code>AssignableScopes</code>; appends <code>active_assignee_name</code>.</p><p><strong>Repository</strong>: <code>AssignmentTrait</code> — Assignment CRUD.</p><p><strong>Hydrate</strong>: <code>AssignmentHydrate</code> — type → <code>input-assignment</code>; <code>assigneeType</code>, <code>assignableType</code>; <code>fetchEndpoint</code>, <code>saveEndpoint</code>; embeds Filepond for attachments.</p><hr><h2 id="translation" tabindex="-1">Translation <a class="header-anchor" href="#translation" aria-label="Permalink to &quot;Translation&quot;">​</a></h2><p><strong>Entity</strong>: <code>IsTranslatable</code>, <code>HasTranslation</code> — Astrotomic Translatable; <code>translations</code> relation; <code>translatedAttributes</code>.</p><p><strong>Repository</strong>: <code>TranslationsTrait</code> — <code>setColumnsTranslationsTrait</code>, <code>prepareFieldsBeforeSaveTranslationsTrait</code>, <code>getFormFieldsTranslationsTrait</code>, <code>filterTranslationsTrait</code>.</p><p><strong>Hydrate</strong>: None (each input Hydrate respects <code>translated: true</code> for locale-aware handling).</p>',91),s=[r];function c(i,n,l,p,h,g){return o(),t("div",null,s)}const m=e(a,[["render",c]]);export{y as __pageData,m as default};
